 1→import type { TagId } from "@/lib/types/primitives";
 2→import type { Tag } from "@/lib/types/tag";
 3→import { useCallback, useMemo, useState } from "react";
 4→
 5→export type SearchQueryTag = {
 6→  id: TagId;
 7→  label: string;
 8→};
 9→
10→export type SearchQuery = {
11→  selectedTags: Array<SearchQueryTag>;
12→  freeText: string;
13→  suggestionPrefix: string;
14→};
15→
16→function extractSuggestionPrefix(freeText: string): string {
17→  const withoutTrailingSpaces = freeText.replace(/\s+$/, "");
18→  if (withoutTrailingSpaces.length === 0) {
19→    return "";
20→  }
21→
22→  const fragments = withoutTrailingSpaces.split(/\s+/);
23→  const trailingFragment = fragments[fragments.length - 1] ?? "";
24→  return trailingFragment.replace(/^#+/, "");
25→}
26→
27→export function useSearchQuery(): {
28→  query: SearchQuery;
29→  addTagFromSuggestion: (tag: Tag, displayLabel?: string) => void;
30→  removeSelectedTag: (tagId: TagId) => void;
31→  setFreeText: (freeText: string) => void;
32→  clearQuery: () => void;
33→} {
34→  const [selectedTags, setSelectedTags] = useState<Array<SearchQueryTag>>([]);
35→  const [freeText, setFreeTextState] = useState("");
36→
37→  const addTagFromSuggestion = useCallback((tag: Tag, displayLabel?: string): void => {
38→    setSelectedTags((previousTags) => {
39→      if (previousTags.some((previousTag) => previousTag.id === tag.id)) {
40→        return previousTags;
41→      }
42→
43→      return [
44→        ...previousTags,
45→        {
46→          id: tag.id,
47→          label: displayLabel ?? tag.label.replace(/^#/, ""),
48→        },
49→      ];
50→    });
51→    setFreeTextState("");
52→  }, []);
53→
54→  const setFreeText = useCallback((nextFreeText: string): void => {
55→    setFreeTextState(nextFreeText);
56→  }, []);
57→
58→  const removeSelectedTag = useCallback((tagId: TagId): void => {
59→    setSelectedTags((previousTags) =>
60→      previousTags.filter((previousTag) => previousTag.id !== tagId)
61→    );
62→  }, []);
63→
64→  const clearQuery = useCallback((): void => {
65→    setSelectedTags([]);
66→    setFreeTextState("");
67→  }, []);
68→
69→  const suggestionPrefix = useMemo((): string => {
70→    return extractSuggestionPrefix(freeText);
71→  }, [freeText]);
72→
73→  const query = useMemo(
74→    (): SearchQuery => ({
75→      selectedTags,
76→      freeText,
77→      suggestionPrefix,
78→    }),
79→    [selectedTags, freeText, suggestionPrefix]
80→  );
81→
82→  return useMemo(
83→    (): {
84→      query: SearchQuery;
85→      addTagFromSuggestion: (tag: Tag, displayLabel?: string) => void;
86→      removeSelectedTag: (tagId: TagId) => void;
87→      setFreeText: (freeText: string) => void;
88→      clearQuery: () => void;
89→    } => ({
90→      query,
91→      addTagFromSuggestion,
92→      removeSelectedTag,
93→      setFreeText,
94→      clearQuery,
95→    }),
96→    [query, addTagFromSuggestion, removeSelectedTag, setFreeText, clearQuery]
97→  );
98→}
99→

  1→import { usePreferences } from "@/features/settings/context/PreferencesContext";
  2→import { getTagDisplayLabel } from "@/features/tags/utils/tagDisplayLabels";
  3→import type { TagId } from "@/lib/types/primitives";
  4→import type { Tag } from "@/lib/types/tag";
  5→import { useCallback, useMemo } from "react";
  6→
  7→const MAX_SUGGESTIONS = 5;
  8→
  9→export type TagSuggestion = {
 10→  id: TagId;
 11→  label: string;
 12→  recipeCount: number;
 13→  countLabel: string;
 14→};
 15→
 16→function normalizePrefix(prefix: string): string {
 17→  return prefix.trim().replace(/^#+/, "").toLowerCase();
 18→}
 19→
 20→function formatCount(recipeCount: number): string {
 21→  if (recipeCount > 99) {
 22→    return "99+";
 23→  }
 24→
 25→  return String(recipeCount);
 26→}
 27→
 28→export function useTagSuggestions({
 29→  tags,
 30→  prefix,
 31→  onSelectSuggestion,
 32→  excludedTagIds = [],
 33→}: {
 34→  tags: Array<Tag>;
 35→  prefix: string;
 36→  onSelectSuggestion: (tag: Tag, displayLabel?: string) => void;
 37→  excludedTagIds?: Array<TagId>;
 38→}): {
 39→  suggestions: Array<TagSuggestion>;
 40→  handleSuggestionPress: (id: TagId) => void;
 41→} {
 42→  const { uiLanguage } = usePreferences();
 43→
 44→  const normalizedPrefix = useMemo(
 45→    (): string => normalizePrefix(prefix),
 46→    [prefix]
 47→  );
 48→
 49→  const tagsById = useMemo((): Map<TagId, Tag> => {
 50→    return new Map(tags.map((tag) => [tag.id, tag]));
 51→  }, [tags]);
 52→
 53→  const excludedTagIdSet = useMemo((): Set<TagId> => {
 54→    return new Set(excludedTagIds);
 55→  }, [excludedTagIds]);
 56→
 57→  const suggestions = useMemo((): Array<TagSuggestion> => {
 58→    return tags
 59→      .filter((tag) => !excludedTagIdSet.has(tag.id))
 60→      .filter((tag) => {
 61→        if (normalizedPrefix.length === 0) {
 62→          return true;
 63→        }
 64→
 65→        const localizedLabel = getTagDisplayLabel(tag.normalizedLabel, uiLanguage);
 66→        return (
 67→          tag.normalizedLabel.startsWith(normalizedPrefix) ||
 68→          localizedLabel.toLowerCase().startsWith(normalizedPrefix)
 69→        );
 70→      })
 71→      .sort((left, right) => {
 72→        if (left.recipeCount !== right.recipeCount) {
 73→          return right.recipeCount - left.recipeCount;
 74→        }
 75→
 76→        return left.normalizedLabel.localeCompare(right.normalizedLabel);
 77→      })
 78→      .slice(0, MAX_SUGGESTIONS)
 79→      .map((tag) => ({
 80→        id: tag.id,
 81→        label: getTagDisplayLabel(tag.normalizedLabel, uiLanguage),
 82→        recipeCount: tag.recipeCount,
 83→        countLabel: formatCount(tag.recipeCount),
 84→      }));
 85→  }, [tags, normalizedPrefix, excludedTagIdSet, uiLanguage]);
 86→
 87→  const handleSuggestionPress = useCallback(
 88→    (id: TagId): void => {
 89→      const tag = tagsById.get(id);
 90→      if (!tag) {
 91→        return;
 92→      }
 93→
 94→      const displayLabel = getTagDisplayLabel(tag.normalizedLabel, uiLanguage);
 95→      onSelectSuggestion(tag, displayLabel);
 96→    },
 97→    [tagsById, onSelectSuggestion, uiLanguage]
 98→  );
 99→
100→  return useMemo(
101→    (): {
102→      suggestions: Array<TagSuggestion>;
103→      handleSuggestionPress: (id: TagId) => void;
104→    } => ({
105→      suggestions,
106→      handleSuggestionPress,
107→    }),
108→    [suggestions, handleSuggestionPress]
109→  );
110→}
111→

 1→import { useEffect, useMemo } from "react";
 2→import { Keyboard, type ViewStyle } from "react-native";
 3→import {
 4→  useAnimatedStyle,
 5→  useSharedValue,
 6→  withSpring,
 7→} from "react-native-reanimated";
 8→
 9→export function useSearchBarVisibilityTransition(
10→  shouldHide: boolean,
11→): {
12→  containerStyle: ViewStyle;
13→} {
14→  const progress = useSharedValue(0);
15→
16→  useEffect(() => {
17→    progress.value = withSpring(shouldHide ? 1 : 0, {
18→      damping: 40,
19→      stiffness: 200,
20→    });
21→  }, [progress, shouldHide]);
22→
23→  useEffect(() => {
24→    if (shouldHide) {
25→      Keyboard.dismiss();
26→    }
27→  }, [shouldHide]);
28→
29→  const containerStyle = useAnimatedStyle(() => ({
30→    opacity: 1 - progress.value,
31→    transform: [
32→      { translateX: -progress.value * 40 },
33→      { scale: 1 - progress.value * 0.05 },
34→    ],
35→  }));
36→
37→  return useMemo(
38→    () => ({
39→      containerStyle,
40→    }),
41→    [containerStyle],
42→  );
43→}
