 1→import { useCallback, useState } from "react";
 2→import { Keyboard } from "react-native";
 3→
 4→function getRandomKey(): string {
 5→  return Math.random().toString(36).substring(2, 15);
 6→}
 7→
 8→export function useSearchFocus(): {
 9→  key: string;
10→  isFocused: boolean;
11→  handleFocus: () => void;
12→  handleBlur: () => void;
13→  handleCancel: () => void;
14→} {
15→  const [isFocused, setIsFocused] = useState(false);
16→  const [key, setKey] = useState(getRandomKey());
17→
18→  const handleFocus = useCallback(() => {
19→    setIsFocused(true);
20→  }, []);
21→
22→  const handleBlur = useCallback(() => {
23→    setIsFocused(false);
24→  }, []);
25→
26→  const handleCancel = useCallback(() => {
27→    setIsFocused(false);
28→    setKey(getRandomKey());
29→    Keyboard.dismiss();
30→  }, [setKey]);
31→
32→  return {
33→    key,
34→    isFocused,
35→    handleFocus,
36→    handleBlur,
37→    handleCancel,
38→  };
39→}
