490→  var onEmptyBackspace: (() -> Void)?
491→
492→  override var intrinsicContentSize: CGSize {
493→    CGSize(width: UIView.noIntrinsicMetric, height: super.intrinsicContentSize.height)
494→  }
495→
496→  override func deleteBackward() {
